sql:
SELECT COUNT(*) 
FROM chapters 
WHERE location = 'San Francisco';

SELECT a.first_name, a.last_name, a.email
FROM awardees a
INNER JOIN awards aw ON a.awardee_id = aw.awardee_id;

SELECT awardees.first_name, awardees.last_name, awards.award_name
FROM awardees
INNER JOIN awards ON awardees.awardee_id = awards.awardee_id;

external_knowledge:
- "springs" refers to the last five years;
- "flowers blooming" and "accolades" both metaphorically represent awards;
- "arranging them in the order of the garden's alphabet" means sorting by chapter names;
- "abundance of blossoms in the recent past" refers to the count of recent awards per chapter.

- "rainmaker" metaphorically refers to the user who has won the most nominations;
- "nomination game" is a metaphor for the process of accumulating nominations;
- "most coveted" implies the award type with the highest number of nominations;
- "top producer of honors" refers to the chapter that has given out the most awards.

sql:
SELECT chapter_name, location, contact_email
FROM chapters
WHERE chapter_id = 1;

SELECT first_name || ' ' || last_name AS full_name
FROM awardees
WHERE awardee_id = 'awardee_id_value';

SELECT awardees.first_name, awardees.last_name, awards.award_name, awards.year_of_award
FROM awardees
INNER JOIN awards ON awardees.awardee_id = awards.awardee_id;

external_knowledge:
- "more accomplished members" refers to awardees with multiple approved awards;
- "since the turn of the century" means from the year 2000 onwards;
- "accolades" refers to the awards received.

sql:
SELECT leader_id, leader_name, email
FROM chapter_leaders
WHERE term_end < date('now', '-5 years');

SELECT chapters.chapter_name, chapter_leaders.leader_name
FROM chapters
INNER JOIN chapter_leaders ON chapters.chapter_id = chapter_leaders.chapter_id;

SELECT first_name, last_name, email 
FROM awardees 
WHERE (strftime('%Y', 'now') - strftime('%Y', member_since)) >= 40;
